esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.follower.count IS NOT NULL
  AND resource.attributes.server.state == "leader"
  AND attributes.state == "unsynced"
// Peak unsynced follower count reported by the leader
| STATS max_unsynced = MAX(metrics.zookeeper.follower.count) BY host.name
// Any unsynced followers risk data loss during failover
// and indicate replication lag or network issues between ensemble members
| WHERE max_unsynced > 0
